window.MUSCLES=[...new Set(LIBRARY.map(e=>e.muscle))].sort();
window.EQUIPS=[...new Set(LIBRARY.map(e=>e.equipment))].sort();
window.PATTERNS=[...new Set(LIBRARY.map(e=>e.pattern))].sort();

window.LIBRARY_MAP = new Map(LIBRARY.map(ex => [ex.name, ex]));
window.LIBRARY_BY_ID = new Map(LIBRARY.map(ex => [ex.id, ex]));

window.LIBRARY_INDEX = (function() {
  const idx = new Map();
  LIBRARY.forEach(ex => {
    [ex.name, ex.muscle, ex.equipment, ex.pattern].join(' ')
      .toLowerCase().split(/\s+/)
      .forEach(tok => {
        if (!idx.has(tok)) idx.set(tok, new Set());
        idx.get(tok).add(ex.id);
      });
  });
  return idx;
})();
